const { BigQuery } = require('@google-cloud/bigquery');
const bigquery = new BigQuery();

exports.processLargeDataset = async (req, res) => {
  // Set timeout and memory limits
  const timeout = 540000; // 540 seconds
  const maxMemory = 8 * 1024 * 1024 * 1024; // 8GB
  
  // Prevent serverless security issues
  if (!req.body || !req.body.query) {
    return res.status(400).send('Invalid request: query required');
  }
  
  const query = req.body.query;
  const options = {
    query: query,
    location: 'US',
    useQueryCache: true,
    useLegacySql: false
  };
  
  try {
    // Execute BigQuery query
    const [job] = await bigquery.createQueryJob(options);
    
    // Process results in chunks to prevent memory issues
    const results = [];
    const chunkSize = 10000;
    
    const processResults = async () => {
      const [rows] = await job.getQueryResults();
      
      // Process in chunks to manage memory
      for (let i = 0; i < rows.length; i += chunkSize) {
        const chunk = rows.slice(i, i + chunkSize);
        // Process chunk here
        results.push(...chunk);
        
        // Allow other operations to run
        await new Promise(resolve => setImmediate(resolve));
      }
      
      return results;
    };
    
    const processedData = await processResults();
    
    // Return aggregated results
    res.status(200).send({
      success: true,
      count: processedData.length,
      data: processedData
    });
    
  } catch (error) {
    console.error('Error processing dataset:', error);
    res.status(500).send({
      success: false,
      error: error.message
    });
  }
};